def _eval_is_zero(self):
    if self.is_commutative is False:
        # issue 10528: there is no way to know if a nc symbol
        # is zero or not
        return
    nz = []
    z = 0
    im_or_z = False
    im = 0
    for a in self.args:
        if a.is_extended_real:
            if a.is_zero:
                z += 1
            elif a.is_zero is False:
                nz.append(a)
            else:
                return
        elif a.is_imaginary:
            im += 1
        elif (S.ImaginaryUnit*a).is_extended_real:
            im_or_z = True
        else:
            return
    if z == len(self.args):
        return True
    if len(nz) == 0 or len(nz) == len(self.args):
        return None
    b = self.func(*nz)
    if b.is_zero:
        if not im_or_z:
            if im == 0:
                return True
            elif im == 1:
                return False
    if b.is_zero is False:
        return False

